public class LossTest : TestBase
{
    [Fact]
    public void FieldRoundtrip_Works()
    {
        var model = new CardDisputes::Loss
        {
            LostAt = DateTimeOffset.Parse("2020-01-31T23:59:59Z"),
            Reason = CardDisputes::LossReason.UserWithdrawn,
        };

        DateTimeOffset expectedLostAt = DateTimeOffset.Parse("2020-01-31T23:59:59Z");
        ApiEnum<string, CardDisputes::LossReason> expectedReason =
            CardDisputes::LossReason.UserWithdrawn;

        Assert.Equal(expectedLostAt, model.LostAt);
        Assert.Equal(expectedReason, model.Reason);
    }

    [Fact]
    public void SerializationRoundtrip_Works()
    {
        var model = new CardDisputes::Loss
        {
            LostAt = DateTimeOffset.Parse("2020-01-31T23:59:59Z"),
            Reason = CardDisputes::LossReason.UserWithdrawn,
        };

        string json = JsonSerializer.Serialize(model, ModelBase.SerializerOptions);
        var deserialized = JsonSerializer.Deserialize<CardDisputes::Loss>(
            json,
            ModelBase.SerializerOptions
        );

        Assert.Equal(model, deserialized);
    }

    [Fact]
    public void FieldRoundtripThroughSerialization_Works()
    {
        var model = new CardDisputes::Loss
        {
            LostAt = DateTimeOffset.Parse("2020-01-31T23:59:59Z"),
            Reason = CardDisputes::LossReason.UserWithdrawn,
        };

        string element = JsonSerializer.Serialize(model, ModelBase.SerializerOptions);
        var deserialized = JsonSerializer.Deserialize<CardDisputes::Loss>(
            element,
            ModelBase.SerializerOptions
        );
        Assert.NotNull(deserialized);

        DateTimeOffset expectedLostAt = DateTimeOffset.Parse("2020-01-31T23:59:59Z");
        ApiEnum<string, CardDisputes::LossReason> expectedReason =
            CardDisputes::LossReason.UserWithdrawn;

        Assert.Equal(expectedLostAt, deserialized.LostAt);
        Assert.Equal(expectedReason, deserialized.Reason);
    }

    [Fact]
    public void Validation_Works()
    {
        var model = new CardDisputes::Loss
        {
            LostAt = DateTimeOffset.Parse("2020-01-31T23:59:59Z"),
            Reason = CardDisputes::LossReason.UserWithdrawn,
        };

        model.Validate();
    }

    [Fact]
    public void CopyConstructor_Works()
    {
        var model = new CardDisputes::Loss
        {
            LostAt = DateTimeOffset.Parse("2020-01-31T23:59:59Z"),
            Reason = CardDisputes::LossReason.UserWithdrawn,
        };

        CardDisputes::Loss copied = new(model);

        Assert.Equal(model, copied);
    }
}

