        Assert.Equal(expectedChargeback, model.Chargeback);
        Assert.Equal(expectedMerchantPrearbitrationDecline, model.MerchantPrearbitrationDecline);
        Assert.Equal(expectedUserPrearbitration, model.UserPrearbitration);
