    [Fact]
    public void OptionalNullablePropertiesSetToNullAreSetToNull_Works()
    {
        var model = new CardDisputes::UserSubmission
        {
            AcceptedAt = DateTimeOffset.Parse("2019-12-27T18:11:19.117Z"),
            Amount = 0,
            AttachmentFiles = [new("file_id")],
            Category = CardDisputes::UserSubmissionCategory.Chargeback,
            CreatedAt = DateTimeOffset.Parse("2019-12-27T18:11:19.117Z"),
            Explanation = "explanation",
            FurtherInformationRequestedAt = DateTimeOffset.Parse("2019-12-27T18:11:19.117Z"),
            FurtherInformationRequestedReason = "further_information_requested_reason",
            Status = CardDisputes::UserSubmissionStatus.Abandoned,
            UpdatedAt = DateTimeOffset.Parse("2019-12-27T18:11:19.117Z"),

            Chargeback = null,
            MerchantPrearbitrationDecline = null,
            UserPrearbitration = null,
        };

        Assert.Null(model.Chargeback);
        Assert.True(model.RawData.ContainsKey("chargeback"));
        Assert.Null(model.MerchantPrearbitrationDecline);
        Assert.True(model.RawData.ContainsKey("merchant_prearbitration_decline"));
        Assert.Null(model.UserPrearbitration);
        Assert.True(model.RawData.ContainsKey("user_prearbitration"));
